import{_ as o,o as a,c as t,a6 as r}from"./chunks/framework.CgU7tkAh.js";const p=JSON.parse('{"title":"Food databases","description":"","frontmatter":{"outline":{"level":[2,4]}},"headers":[],"relativePath":"admin/locales/fdbs.md","filePath":"admin/locales/fdbs.md"}'),d={name:"admin/locales/fdbs.md"};function i(s,e,n,c,l,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="food-databases" tabindex="-1">Food databases <a class="header-anchor" href="#food-databases" aria-label="Permalink to “Food databases”">​</a></h1><p><code>Food databases</code> or <code>food lists</code> are list of food records attached to locale record.</p><p>Foods are organized in categories and subcategories in tree-like structure.</p><p>Food database editor offers tree-like structure browsing of <code>category</code> / <code>food</code> records.</p><p>Most of the properties are similar between <code>category</code> and <code>food</code> records with few specific exceptions.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="code" tabindex="-1">Code <a class="header-anchor" href="#code" aria-label="Permalink to “Code”">​</a></h3><p>Locale-unique code for the category or food record. Used for linking records across locales.</p><h3 id="english-name" tabindex="-1">English name <a class="header-anchor" href="#english-name" aria-label="Permalink to “English name”">​</a></h3><p>English name of the category or food record. Used for internal purposes and as fallback when locale specific name is not available.</p><h3 id="local-name" tabindex="-1">Local name <a class="header-anchor" href="#local-name" aria-label="Permalink to “Local name”">​</a></h3><p>Localized name of the category or food record.</p><h3 id="icon" tabindex="-1">Icon <a class="header-anchor" href="#icon" aria-label="Permalink to “Icon”">​</a></h3><p>Icon for the category or food record.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Intake24 is using <a href="https://icon-sets.iconify.design/" target="_blank" rel="noreferrer">iconify</a> icons. Any icon from the iconify collection can be used as food icon. However not all icons are being bundled with Intake24, so if you want to use an icon that is not bundled, the technical team will need to be contacted to add the icon to the bundle.</p></div><h3 id="hidden-category-only" tabindex="-1">Hidden (<code>category-only</code>) <a class="header-anchor" href="#hidden-category-only" aria-label="Permalink to “Hidden (category-only)”">​</a></h3><p>Option to set category record as hidden. Will be excluded from global food search.</p><h3 id="tags" tabindex="-1">Tags <a class="header-anchor" href="#tags" aria-label="Permalink to “Tags”">​</a></h3><p>List of tags attached to category or food record. Can be used for various purposes, e.g. setting up conditional logic in prompts.</p><h3 id="alternative-names-foods-only" tabindex="-1">Alternative names (<code>foods-only</code>) <a class="header-anchor" href="#alternative-names-foods-only" aria-label="Permalink to “Alternative names (foods-only)”">​</a></h3><p>List of alternative names for the food record. Used for foods which are known under different names in different regions or by different groups of people.</p><h2 id="categories" tabindex="-1">Categories <a class="header-anchor" href="#categories" aria-label="Permalink to “Categories”">​</a></h2><p>List of parent categories the category or food is attached to.</p><h2 id="attributes" tabindex="-1">Attributes <a class="header-anchor" href="#attributes" aria-label="Permalink to “Attributes”">​</a></h2><p>Attributes are inhered from default attribute values and can either set as inherited or overridden.</p><ul><li><code>inherited</code> - when set to inherited, attribute value is inherited from parent category. Algorithm goes through the parent categories until it finds a record with overridden value for the attribute.</li><li><code>overridden</code> - when set to overridden, attribute value is set specifically for the category or food record and is not inherited from parent category.</li></ul><p><strong>Attributes list:</strong></p><ul><li><p><code>same as before</code> - flag whether the food should be used for <code>same-as-before</code> prompt functionality</p></li><li><p><code>ready-made food</code> - flag whether the food is should be used for <code>ready-made</code> prompt functionality</p></li><li><p><code>reasonable amount</code> - food portion size amount (g) to be considered as <code>reasonable</code></p></li><li><p><code>use for recipes</code></p></li></ul><h2 id="nutrient-table-records-foods-only" tabindex="-1">Nutrient table records (foods-only) <a class="header-anchor" href="#nutrient-table-records-foods-only" aria-label="Permalink to “Nutrient table records (foods-only)”">​</a></h2><p>List nutrient table records attached to food record.</p><h2 id="portion-size-methods" tabindex="-1">Portion size methods <a class="header-anchor" href="#portion-size-methods" aria-label="Permalink to “Portion size methods”">​</a></h2><p>List of portion size methods attached to food record. See <a href="/admin/locales/portion-sizes">portion size methods documentation</a> for more details on portion size methods.</p><h2 id="associated-foods-foods-only" tabindex="-1">Associated foods (foods-only) <a class="header-anchor" href="#associated-foods-foods-only" aria-label="Permalink to “Associated foods (foods-only)”">​</a></h2><p>List of associated foods attached to food record.</p><ul><li><p><code>association</code> - food can either be associated with <code>food</code> or <code>category</code> record</p></li><li><p><code>link as main</code> - flag whether the associated food should be linked as main food</p></li><li><p><code>allow multiple foods</code> - flag whether multiple associated foods can be selected in the same prompt</p></li><li><p><code>generic name</code> - localized generic name of the food</p></li><li><p><code>text</code> - localized question to be asked</p></li></ul>',35)])])}const b=o(d,[["render",i]]);export{p as __pageData,b as default};
